    let m=txt.match(/(?:km|kms|kil[oó]metro|progresiva|distancia|punto|hito|ruta)\D{0,28}(-?\d+(?:[\.,]\d+)?)/i) || txt.match(/(-?\d+(?:[\.,]\d+)?)\s*(?:km|kms|kil[oó]metro)/i);
