      const w=await fetchWeatherRichV227(c);
      const r=route(t);
      const left=`<div class="climaDriver227"><b>Chofer:</b> ${sx(driver(t)||'-')}</div><div class="climaLoc227">${sx(locx(t)||'-')}</div>`;
