      const bottom=`${kv('Embarque',embVal(t)||'-')}${kv('Cliente',r.cliente||'-')}${kv('Sensación',(w.sens??'-')+'°')}${kv('Viento',(w.wind??'-')+' km/h')}${kv('Humedad',(w.hum??'-')+(w.hum==='-'?'':'%'))}${kv('Visibilidad',(w.vis??'-')+(w.vis==='-'?'':' km'))}${kv('Lluvia',(w.rain??'-')+(w.rain==='-'?'':' mm'))}`;
