/* ===== v3.3.41 - Entregas: abreviatura en origen del render ===== */
window.abreviarHitoEntrega186 = function(txt){
  const original = String(txt || '').trim();
  const n = original.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').trim();
  if(/^clz\b/.test(n) || n.includes('centro logistico zarate') || n.includes('centro logistico zárate')) return 'CLZ';
  if(/^clc\b/.test(n) || n.includes('centro logistico cordoba') || n.includes('centro logistico córdoba')) return 'CLC';
  return original;
};

