const clean=v=>{if(v===undefined||v===null)return'';if(typeof v==='object'){if(v&&typeof v.toDate==='function')return v;for(const k of ['nombre','name','label','title','descripcion','description','aduana','aduanaId','destino','origen','pais','country','provincia','tipo','estado','level','localidad','ciudad']){const c=clean(v[k]);if(c)return c}return''}const s=String(v).trim();return(!s||/^(\[object object\]|object object|undefined|null)$/i.test(s))?'':s};
