const norm=v=>clean(v).toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').trim();
const get=(o,ks)=>{for(const k of ks){const v=o&&o[k];const c=clean(v);if(c)return v}return''};
