function country(v){const s=norm(v);if(/(tierra del fuego|ushuaia|rio grande|tolhuin|antartida|islas del atlantico sur)/.test(s))return'tdf';if(/(chile|stli|los andes|libertadores|cl\b|toyota chile)/.test(s))return'chile';if(/(paraguay|asuncion|puerto jose falcon|falcon|clorinda|py\b|garden paraguay)/.test(s))return'paraguay';if(/(uruguay|montevideo|fray bentos|uy\b)/.test(s))return'uruguay';if(/(brasil|brazil|curitiba|sao paulo|br\b)/.test(s))return'brasil';return'argentina'}
function aduanas(){return[].concat(Array.isArray(window.aduanas)?window.aduanas:[],Array.isArray(window.aduana)?window.aduana:[],Array.isArray(window.aduana_registros)?window.aduana_registros:[]).filter(Boolean)}
