/* ===== v3.3.41 - Entregas: ajuste final camion/textos ===== */
(function(){
  const CSS = '\n/* ===== v3.3.41 - Entregas: camion sobre linea y textos de hitos destacados =====\n   SOLO afecta #entrega. No modifica otros módulos. */\n\n#entrega .entregaTimeline{\n  --entrega-progress:0;\n}\n\n/* Camión anclado al mismo eje útil de la línea de tiempo.\n   Evita que quede fuera cuando el avance es 0%. */\n#entrega .entregaVehicle{\n  left:calc(72px + (100% - 144px) * var(--entrega-progress)) !important;\n  transform:translateX(-50%) !important;\n  z-index:6 !important;\n}\n\n/* Texto de hitos con fondo claro y texto negro para mejorar lectura */\n#entrega .entregaStep b{\n  display:inline-block !important;\n  background:rgba(255,255,255,.92) !important;\n  color:#111827 !important;\n  border-radius:6px !important;\n  padding:3px 6px !important;\n  box-shadow:0 2px 6px rgba(0,0,0,.28) !important;\n  line-height:1.05 !important;\n  max-width:100% !important;\n}\n\n#entrega .entregaStep em{\n  display:inline-block !important;\n  background:rgba(255,255,255,.84) !important;\n  color:#111827 !important;\n  border-radius:5px !important;\n  padding:2px 5px !important;\n  margin-top:5px !important;\n  box-shadow:0 2px 5px rgba(0,0,0,.22) !important;\n}\n\n#entrega .entregaStep.timelineStart b,\n#entrega .entregaStep.timelineStart em{\n  text-align:left !important;\n}\n\n#entrega .entregaStep.timelineEnd b,\n#entrega .entregaStep.timelineEnd em{\n  text-align:right !important;\n}\n';
  function injectEntrega164(){
    let st=document.getElementById('entrega-v164-camion-textos-css');
    if(!st){
      st=document.createElement('style');
      st.id='entrega-v164-camion-textos-css';
      document.head.appendChild(st);
    }
    st.textContent=CSS;
  }
  function fixCamion164(){
    document.querySelectorAll('#entrega .entregaTimeline').forEach(tl=>{
      const line = tl.querySelector('.entregaLine i');
      let pct = 0;
      if(line && line.style.width){
        const n = parseFloat(line.style.width);
        if(!Number.isNaN(n)) pct = Math.max(0, Math.min(100, n));
      }
      tl.style.setProperty('--entrega-progress', String(pct/100));
      const veh = tl.querySelector('.entregaVehicle');
      if(veh){
        veh.style.left = 'calc(72px + (100% - 144px) * var(--entrega-progress))';
        veh.style.transform = 'translateX(-50%)';
      }
    });
  }
  function run164(){
    injectEntrega164();
    setTimeout(fixCamion164, 0);
    setTimeout(fixCamion164, 120);
  }
  document.addEventListener('DOMContentLoaded', run164);
  window.addEventListener('load', run164);
  const oldRenderEntrega164 = window.renderEntrega;
  if(typeof oldRenderEntrega164 === 'function' && !oldRenderEntrega164.__v164){
    window.renderEntrega = async function(){
      const r = await oldRenderEntrega164.apply(this, arguments);
      run164();
      return r;
    };
    window.renderEntrega.__v164 = true;
  }
  setInterval(()=>{ if(document.querySelector('#entrega .entregaTimeline')) fixCamion164(); }, 1200);
})();




