  const oldRender=window.renderEntrega;
  if(typeof oldRender==='function' && !oldRender.__wireOnly172_disabled223){
    window.renderEntrega=async function(){
      const r=await oldRender.apply(this, arguments);
      wire();
      return r;
    };
    window.renderEntrega.__wireOnly172_disabled223=true;
  }

