/* ===== v3.3.41 - Entregas: cierre marca último hito =====
   Solo afecta la marcación visual de tarjetas cerradas en Entregas. */
(function(){
  const VERSION_ENTREGA_192='3.3.41';
  window.ELTA_APP_VERSION=VERSION_ENTREGA_192;
  window.APP_VERSION_V2=VERSION_ENTREGA_192;

  function isClosedCard192(card){
    const txt=(card.textContent||'').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'');
    return /\bcerrado\b/.test(txt);
  }

  function fixClosedTimeline192(){
    document.querySelectorAll('#entrega .entregaCard').forEach(card=>{
      if(!isClosedCard192(card)) return;
      const tl=card.querySelector('.entregaTimeline');
      if(!tl) return;

      const steps=[...tl.querySelectorAll('.entregaStep')];
      if(!steps.length) return;

      const last=steps[steps.length-1];
      steps.forEach(s=>s.classList.add('done'));
      steps.forEach(s=>s.classList.remove('current'));
      last.classList.add('done','current','hasDate','timelineEnd');

      const line=tl.querySelector('.entregaLine i');
      if(line) line.style.width='100%';

      tl.style.setProperty('--entrega-progress','1');

      const veh=tl.querySelector('.entregaVehicle');
      if(veh){
        veh.style.left='calc(72px + (100% - 144px) * 1)';
        veh.style.transform='translateX(-50%)';
      }

      const lastDate=last.querySelector('em');
      if(lastDate && (!lastDate.textContent || lastDate.textContent.trim()==='-')){
        const upd=(card.querySelector('.entregaBottom span:first-child')?.textContent||'').replace(/Actualizado:\s*/i,'').trim();
        if(upd) lastDate.textContent=upd;
      }
    });
  }

  const oldRender192=window.renderEntrega;
  if(typeof oldRender192==='function' && !oldRender192.__cierreFinal192){
    window.renderEntrega=async function(){
      const r=await oldRender192.apply(this,arguments);
      fixClosedTimeline192();
      requestAnimationFrame(fixClosedTimeline192);
      setTimeout(fixClosedTimeline192,80);
      return r;
    };
    window.renderEntrega.__cierreFinal192=true;
  }

  const oldTab192=window.tab;
  if(typeof oldTab192==='function' && !oldTab192.__cierreFinal192){
    window.tab=function(id){
      const r=oldTab192.apply(this,arguments);
      if(id==='entrega'){
        fixClosedTimeline192();
        requestAnimationFrame(fixClosedTimeline192);
        setTimeout(fixClosedTimeline192,80);
      }
      return r;
    };
    window.tab.__cierreFinal192=true;
  }

  document.addEventListener('DOMContentLoaded',()=>setTimeout(fixClosedTimeline192,120));
  window.addEventListener('load',()=>setTimeout(fixClosedTimeline192,120));
})();




/* ===== v3.3.41 - Entregas: cierre gana contra render heredado tardío =====
   Solo afecta la vista Entregas. Corrección finita, sin observer ni intervalos. */
(function(){
  const VERSION_ENTREGA_193='3.3.41';
  window.ELTA_APP_VERSION=VERSION_ENTREGA_193;
  window.APP_VERSION_V2=VERSION_ENTREGA_193;

  function cardClosed193(card){
    const stateText = [
      card.querySelector('.entregaStatus')?.textContent || '',
      card.querySelector('.entregaMeta .state')?.textContent || '',
      card.querySelector('.entregaBottom')?.textContent || '',
      card.textContent || ''
    ].join(' ').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'');
    return /\bcerrado\b/.test(stateText);
  }

  function markClosed193(card){
    if(!card || !cardClosed193(card)) return;
    const tl = card.querySelector('.entregaTimeline');
    if(!tl) return;

    const steps = [...tl.querySelectorAll('.entregaStep')];
    if(!steps.length) return;

    const last = steps[steps.length - 1];

    steps.forEach(step => {
      step.classList.add('done');
      step.classList.remove('current');
    });

    last.classList.add('done','hasDate','timelineEnd');
    last.classList.remove('current');

    const prog = tl.querySelector('.entregaLine i');
    if(prog) prog.style.width = '100%';

    tl.style.setProperty('--entrega-progress','1');

    const veh = tl.querySelector('.entregaVehicle');
    if(veh){
      veh.style.left = 'calc(72px + (100% - 144px) * 1)';
      veh.style.transform = 'translateX(-50%)';
    }

    const lastEm = last.querySelector('em');
    if(lastEm && (!lastEm.textContent || lastEm.textContent.trim()==='-')){
      const upd = (card.querySelector('.entregaBottom span:first-child')?.textContent || '')
        .replace(/Actualizado:\s*/i,'')
        .trim();
      if(upd) lastEm.textContent = upd;
    }

    const metaNext = card.querySelectorAll('.entregaMeta b')[2];
    if(metaNext && /toyota chile|garden paraguay|sevel uruguay|cierre|destino/i.test(metaNext.textContent || '')){
      metaNext.textContent = 'Tránsito finalizado';
    }

    const bottom = card.querySelector('.entregaBottom');
    if(bottom){
      bottom.querySelectorAll('span').forEach(span=>{
        if(/^\s*Pr[oó]ximo hito\s*:/i.test(span.textContent || '')){
          const b = span.querySelector('b');
          if(b) span.innerHTML = '<b>Próximo hito:</b> Tránsito finalizado';
        }
      });
    }
  }

  function fixClosed193(){
    document.querySelectorAll('#entrega .entregaCard').forEach(markClosed193);
  }

  function scheduleClosedFix193(){
    fixClosed193();
    requestAnimationFrame(fixClosed193);
    [60,140,300,600,1000,1600].forEach(ms=>setTimeout(fixClosed193,ms));
  }

  const oldRender193 = window.renderEntrega;
  if(typeof oldRender193 === 'function' && !oldRender193.__cierrePost193){
    window.renderEntrega = async function(){
      const r = await oldRender193.apply(this, arguments);
      scheduleClosedFix193();
      return r;
    };
    window.renderEntrega.__cierrePost193 = true;
  }

  const oldTab193 = window.tab;
  if(typeof oldTab193 === 'function' && !oldTab193.__cierrePost193){
    window.tab = function(id){
      const r = oldTab193.apply(this, arguments);
      if(id === 'entrega') scheduleClosedFix193();
      return r;
    };
    window.tab.__cierrePost193 = true;
  }

  document.addEventListener('DOMContentLoaded',()=>setTimeout(scheduleClosedFix193,200));
  window.addEventListener('load',()=>setTimeout(scheduleClosedFix193,200));
})();




