/* ===== v3.3.41 - Entregas: botón Actualizar con render único =====
   Solo afecta el botón Actualizar de Entregas.
   Evita que un handler heredado vuelva a pintar datos anteriores, especialmente Última act. */
(function(){
  const VERSION_ENTREGA_195='3.3.41';
  window.ELTA_APP_VERSION=VERSION_ENTREGA_195;
  window.APP_VERSION_V2=VERSION_ENTREGA_195;
  let busy195=false;
  let lastData195=null;

  async function readCol195(name){
    try{
      const dbc = window.db || (typeof db !== 'undefined' ? db : null);
      if(dbc && typeof dbc.collection === 'function'){
        const snap = await dbc.collection(name).get();
        return snap.docs.map(d=>({id:d.id,_docId:d.id,...d.data()}));
      }
    }catch(e){ console.warn('Entregas v195 read', name, e); }
    try{
      if(window.firebase && window.firebase.firestore){
        const snap = await window.firebase.firestore().collection(name).get();
        return snap.docs.map(d=>({id:d.id,_docId:d.id,...d.data()}));
      }
    }catch(e){}
    return null;
  }

  async function reloadData195(){
    const [tr, em, ad] = await Promise.all([
      readCol195('transitos'),
      readCol195('embarque'),
      readCol195('aduana')
    ]);
    if(Array.isArray(tr)){ window.trs=tr; try{ trs=tr; }catch(_e){} }
    if(Array.isArray(em)){ window.embarques=em; try{ embarques=em; }catch(_e){} }
    if(Array.isArray(ad)){ window.aduanas=ad; }
    lastData195={tr,em,ad,ts:Date.now()};
  }

  function applyClosed195(){
    if(typeof window.__applyClosedEntrega194 === 'function'){
      try{ window.__applyClosedEntrega194(); }catch(e){}
    }
    document.querySelectorAll('#entrega .entregaCard').forEach(card=>{
      const txt=[
        card.querySelector('.entregaStatus')?.textContent||'',
        card.querySelector('.entregaMeta .state')?.textContent||'',
        card.querySelector('.entregaBottom')?.textContent||''
      ].join(' ').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'');
      if(!/\bcerrado\b/.test(txt)) return;
      card.classList.add('closedTransit');
      const tl=card.querySelector('.entregaTimeline');
      if(!tl) return;
      tl.style.setProperty('--entrega-progress','1');
      const line=tl.querySelector('.entregaLine i');
      if(line) line.style.width='100%';
      const steps=[...tl.querySelectorAll('.entregaStep')];
      steps.forEach(s=>{s.classList.add('done');s.classList.remove('current');});
      const last=steps[steps.length-1];
      if(last) last.classList.add('done','hasDate','timelineEnd');
      const veh=tl.querySelector('.entregaVehicle');
      if(veh){veh.style.left='calc(72px + (100% - 144px) * 1)';veh.style.transform='translateX(-50%)';}
    });
  }

  async function finalRefresh195(btn){
    if(busy195) return false;
    busy195=true;
    const b=btn || document.querySelector('#entrega .entregaRefreshBtn');
    const old=b ? b.textContent : 'Actualizar';
    if(b){ b.disabled=true; b.textContent='Actualizando...'; }
    try{
      await reloadData195();
      if(typeof window.renderEntrega === 'function'){
        await window.renderEntrega(false);
      }
      applyClosed195();

      // Gana contra renders tardíos heredados: todos usan los mismos datos frescos.
      /* v3.3.41: renders tardíos heredados desactivados */
    }finally{
      setTimeout(()=>{
        if(b){ b.disabled=false; b.textContent=old || 'Actualizar'; }
        busy195=false;
        wire195();
      },140);
    }
    return false;
  }

  function wire195(){
    document.querySelectorAll('#entrega .entregaRefreshBtn').forEach(btn=>{
      btn.onclick=function(ev){
        ev.preventDefault();
        ev.stopPropagation();
        if(ev.stopImmediatePropagation) ev.stopImmediatePropagation();
        finalRefresh195(btn);
        return false;
      };
    });
  }

  // Reemplaza funciones viejas usadas por los handlers anteriores.
  window.forceEntregaRefresh195=finalRefresh195;
  window.forceEntregaRefresh174=finalRefresh195;
  window.forceEntregaIsolatedRefresh173=finalRefresh195;
  window.forceEntregaIsolatedRefresh172=finalRefresh195;
  window.forceEntregaInlineRefresh171=finalRefresh195;
  window.forceEntregaCleanRefresh170=finalRefresh195;
  window.forceEntregaHardRefresh169=finalRefresh195;
  window.forceRefreshEntrega168=finalRefresh195;

  document.addEventListener('click',function(ev){
    const btn=ev.target && ev.target.closest ? ev.target.closest('#entrega .entregaRefreshBtn') : null;
    if(!btn) return;
    ev.preventDefault();
    ev.stopPropagation();
    if(ev.stopImmediatePropagation) ev.stopImmediatePropagation();
    finalRefresh195(btn);
  },true);

  document.addEventListener('DOMContentLoaded',()=>setTimeout(wire195,100));
  window.addEventListener('load',()=>setTimeout(wire195,100));
  setInterval(wire195,900);
})();




/* ===== v3.3.41 - Entregas: fecha correcta de cierre y última actualización =====
   Solo afecta Entregas. Toma la fecha más nueva de registros del tránsito para cerrado. */
(function(){
  const VERSION_ENTREGA_196='3.3.41';
  window.ELTA_APP_VERSION=VERSION_ENTREGA_196;
  window.APP_VERSION_V2=VERSION_ENTREGA_196;

  function parseDate196(txt){
    if(!txt) return null;
    // Soporta formatos dd/mm, hh:mm usados visualmente; se usa solo para no borrar fechas.
    return String(txt).trim();
  }

  function cardClosed196(card){
    const txt=[
      card.querySelector('.entregaStatus')?.textContent||'',
      card.querySelector('.entregaMeta .state')?.textContent||'',
      card.querySelector('.entregaBottom')?.textContent||''
    ].join(' ').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'');
    return /\bcerrado\b/.test(txt);
  }

  function fixClosedDates196(){
    document.querySelectorAll('#entrega .entregaCard').forEach(card=>{
      if(!cardClosed196(card)) return;
      const metaUpd=card.querySelector('.entregaMeta:nth-of-type(1) b');
      const bottomUpd=card.querySelector('.entregaBottom span:first-child');
      const last=card.querySelector('.entregaTimeline .entregaStep:last-of-type em');
      const currentLast=last ? parseDate196(last.textContent) : '';
      const currentUpd=metaUpd ? parseDate196(metaUpd.textContent) : '';
      // Si el último hito tiene fecha y Última act. quedó vieja, usar la fecha del último hito.
      if(currentLast && currentLast !== '-' && metaUpd && currentUpd !== currentLast){
        metaUpd.textContent=currentLast;
        if(bottomUpd) bottomUpd.innerHTML='<b>Actualizado:</b> '+currentLast;
      }
    });
  }

  const oldRender196=window.renderEntrega;
  if(typeof oldRender196==='function' && !oldRender196.__fechaCierre196){
    window.renderEntrega=async function(){
      const r=await oldRender196.apply(this,arguments);
      fixClosedDates196();
      requestAnimationFrame(fixClosedDates196);
      setTimeout(fixClosedDates196,160);
      setTimeout(fixClosedDates196,500);
      return r;
    };
    window.renderEntrega.__fechaCierre196=true;
  }

  const oldTab196=window.tab;
  if(typeof oldTab196==='function' && !oldTab196.__fechaCierre196){
    window.tab=function(id){
      const r=oldTab196.apply(this,arguments);
      if(id==='entrega'){
        fixClosedDates196();
        requestAnimationFrame(fixClosedDates196);
        setTimeout(fixClosedDates196,160);
      }
      return r;
    };
    window.tab.__fechaCierre196=true;
  }
})();




